        {
          "@type": "Question",
          "name": "How is a landowner's share of constructed area valued in a joint development agreement?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "The consideration is the stamp duty value of the landowner's share of the built up area on the date the completion certificate is issued, plus any cash received. If a developer hands over twelve flats with a stamp duty value of Rs 6 crore and also pays Rs 50 lakh, the full value of consideration is Rs 6.5 crore."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between a joint development agreement and an outright land sale?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "In an outright sale the landowner transfers title for cash and pays capital gains immediately, while in a joint development agreement the landowner retains an interest and receives built up area or a share of revenue. The developer funds approvals and construction. Registration, stamp duty and the point at which capital gains arise all differ."
          }
        },
        {
          "@type": "Question",
          "name": "When does capital gains tax arise for a landowner under Section 45(5A)?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "For an individual or Hindu undivided family, capital gains under a joint development agreement are taxed in the year the completion certificate for the whole or part of the project is issued, not when the agreement is signed. The deferral is lost if the landowner transfers the share before that date, moving tax to the year of transfer."
          }
        }
